val colorList = listOf(
    Color(DEFAULT_SEED_COLOR),
    Color.Blue,
    Hct(60.0, 100.0, 70.0).toSrgb().toColor(),
    Hct(125.0, 50.0, 60.0).toSrgb().toColor(),
    Color.Cyan,
    Color.Red,
    Color.Yellow,
    Color.Magenta
)

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun Appearance(
    onBackPressed: () -> Unit, navigateToDarkTheme: () -> Unit
) {

    Scaffold(topBar = {
        LargeTopAppBar(title = {
            Text(
                text = stringResource(id = R.string.display),
                style = MaterialTheme.typography.headlineLarge
            )
        }, navigationIcon = {
            BackButton {
                onBackPressed()
            }
        })
    }) {
        Column(
            Modifier.padding(it),
            verticalArrangement = Arrangement.spacedBy(10.dp)
        ) {
            Column {
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(horizontal = 24.dp)
                        .aspectRatio(1.38f)
                        .clip(RoundedCornerShape(24.dp))
                        .background(
                            MaterialTheme.colorScheme.inverseOnSurface
                        )
                        .clickable { },
                    horizontalArrangement = Arrangement.Center,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    DynamicSVGImage(
                        modifier = Modifier.padding(60.dp),
                        contentDescription = "palette",
                        svgString = PALETTE
                    )
                }
                Spacer(modifier = Modifier.height(24.dp))

                val pagerState = rememberPagerState(initialPage = colorList.indexOf(Color(
                    LocalSeedColor.current))
                        .run { if (equals(-1)) 1 else this })
                HorizontalPager(
                    modifier = Modifier
                        .fillMaxWidth()
                        .clearAndSetSemantics { }, state = pagerState,
                    count = colorList.size, contentPadding = PaddingValues(horizontal = 12.dp)
                ) {
                    Row {
                        ColorButtons(colorList[it],last = it == colorList.lastIndex)
                    }
                }
                HorizontalPagerIndicator(
                    pagerState = pagerState,
                    pageCount = colorList.size,
                    modifier = Modifier
                        .clearAndSetSemantics { }
                        .align(Alignment.CenterHorizontally)
                        .padding(vertical = 12.dp),
                    activeColor = MaterialTheme.colorScheme.primary,
                    inactiveColor = MaterialTheme.colorScheme.outlineVariant,
                    indicatorHeight = 6.dp,
                    indicatorWidth = 6.dp
                )
            }
            if (DynamicColors.isDynamicColorAvailable()) {
                PreferenceSwitch(title = stringResource(id = R.string.dynamic_color),
                    description = stringResource(
                        id = R.string.dynamic_color_desc
                    ),
                    icon = Icons.Outlined.Palette,
                    isChecked = LocalDynamicColorSwitch.current,
                    onClick = {
                        switchDynamicColor()
                    })
            }

            SettingItem(
                title = stringResource(id = R.string.dark_theme),
                description = LocalDarkTheme.current.getDarkThemeDesc(),
                icon = Icons.Outlined.DarkMode,
            ) { navigateToDarkTheme() }

            Subtitle(text = stringResource(id = R.string.button_shape))
            val buttonShapes = listOf("Default", "Circles", "Triangles", "Star")
            val currentShape = AppSettingsStateFlow.collectAsState().value.buttonShape

            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                buttonShapes.forEach { shape ->
                    ButtonShapeItem(
                        shapeName = shape,
                        isSelected = currentShape == shape,
                        onClick = { modifyButtonShape(shape) }
                    )
                }
            }
        }
    }
}

@Composable
fun RowScope.ButtonShapeItem(
    shapeName: String,
    isSelected: Boolean,
    onClick: () -> Unit
) {
    val shape = getButtonShape(shapeName)
    val containerColor = if (isSelected) MaterialTheme.colorScheme.primaryContainer else MaterialTheme.colorScheme.surfaceVariant
    val contentColor = if (isSelected) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurfaceVariant

