                        modifier = Modifier.padding(PaddingValues(start = 24.dp, end = 12.dp, top = 16.dp))
                    )
                })
        }
    }
    if (showTimePickerDialog) {
        TimePickerDialog(
            onTimeSelected = { hour, minutes ->
                showTimePickerDialog = false
                datePickerState.selectedDateMillis?.let {
                    onDateTimeSelected(
                        getDateTimeInMillis(
                            it,
                            hour,
                            minutes
                        )
                    )
                }
                onDismiss()
            },
            onDismiss = {
                showTimePickerDialog = false
                onDismiss()
            }
        )
    }
}

